create table dirkspzm32.lvs_lte_hist (
    sid                      varchar2(2 char) not null enable,
    firma_nr                 number(2, 0) not null enable,
    lte_id                   varchar2(20 char) not null enable,
    lte_name                 varchar2(22 char),
    lgr_ort                  number(5, 0),
    lgr_platz                varchar2(30 char),
    lgr_platz_gruppe         varchar2(30 char),
    lte_vol_hoehe            number(5, 0),
    lte_vol_breite           number(5, 0),
    lte_vol_tiefe            number(5, 0),
    lte_vol                  number(6, 3),
    lte_akt_kg               number(*, 6),
    lte_akt_lhm              number(*, 0),
    ls_login_id              number(*, 0),
    lte_letzte_buchung       timestamp(6),
    lte_status               varchar2(2 char),
    lte_voll                 varchar2(1 char),
    ziel_lgr_ort             number(5, 0),
    ziel_lgr_platz           varchar2(30 char),
    nve_nr                   varchar2(19 char),
    min_temp                 number(*, 5) default - 300 not null enable,
    max_temp                 number(*, 5) default + 300 not null enable,
    abc                      number(*, 0) default 1 not null enable,
    wert_klasse              number(*, 0) default 0 not null enable,
    gefahren_klasse          number(*, 0) default 0 not null enable,
    waren_typ                varchar2(3 char) default 'LP' not null enable,
    res_string               varchar2(80 char),
    res_artikel_id           varchar2(30 char),
    res_mhd                  date,
    order_vorgang_id         number(*, 0),
    res_string_statisch      varchar2(50 char),
    ziel_lgr_ort_n_freif     number(5, 0),
    ziel_lgr_platz_n_freif   varchar2(30 char),
    order_auf_id             number(*, 0),
    lte_inv_status           varchar2(1 char),
    anz_uml                  number(*, 0),
    lte_eti_druck_status     varchar2(10 char),
    res_login_id             number(*, 0),
    res_ziel_lgr_platz       varchar2(30 char),
    packschema_kopf_id       varchar2(20 char),
    transport_gruppe         number(*, 5),
    lkw_nr                   number(*, 5),
    lte_offset_x             number(*, 5),
    lte_offset_y             number(*, 5),
    lte_offset_z             number(*, 5),
    auto_depal               varchar2(10 char),
    wickelprogramm           varchar2(4 char),
    wickelprogramm_einl      varchar2(4 char),
    komm_menge_kontrolle     varchar2(2 char) default 'N',
    akt_inventur_id          number(*, 0),
    letzte_inventur_id       number(*, 0),
    letzte_inventur_datum    date,
    letzte_inventur_login_id number(*, 0)
);

alter table dirkspzm32.lvs_lte_hist
    add constraint pk_lvs_lte_hist primary key ( lte_id )
        using index enable;


